var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"좋아. 이 버튼을 누르면 되는 거였지?","JPN":"よし。このボタンを押せばいいんだよな？","ENG":"All right. I just press this button, right?","TWN":"好。按這個按鍵就可以了對吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"……됐다!","JPN":"……ついた！","ENG":"...Done!","TWN":"……好了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L5_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"거, 검은 화면밖에 안 잡히는데…… 잘못 누른 거 아닐까?","JPN":"が、画面が真っ黒だけど……ボタンを間違えたんじゃないかな？","ENG":"I-I think it's only showing a black screen... Maybe you hit the wrong button...?","TWN":"呃，只拍到黑畫面耶……是不是按錯了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"엥? 이 버튼을 누르는 거 아니었어?","JPN":"あ？　このボタンじゃなかったのか？","ENG":"Huh? Isn't it this button?","TWN":"欸？不是按這個嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"왜 안 켜지는 건데 이 망할 카메라!","JPN":"何で動かないんだよ、このクソカメラ！","ENG":"Why won't this stupid camera turn on already?!","TWN":"這該死的相機為什麼打不開啊！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L8_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그런다고 고쳐지겠어? 무식하게 힘으로 해결한다고 되는 게 아니라고.","JPN":"それで直るわけないでしょ？　何でも力で解決できるわけじゃないのよ。","ENG":"Do you think that will fix it? You cannot solve everything with brute strength.","TWN":"你那樣就會修好嗎？這不是靠蠻力就能解決的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"넌 옆에서 아무것도 안 하잖아 이 멸치야!","JPN":"お前は何もしてねぇだろ、イワシ！","ENG":"You're just standing there doing nothing, Weak Sauce!","TWN":"你這小魚乾在旁邊什麼忙都沒幫啊！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"얘, 얘들아. 카메라 앞에서 싸우면 안 돼…….","JPN":"ふ、二人とも、カメラの前で喧嘩しちゃダメだよ……","ENG":"G-girls. We shouldn't fight in front of the camera...","TWN":"喂、喂，你們不要在鏡頭前吵架啦……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"소빈이 말이 맞아. 지금은 사이좋은 모습 보여주자.","JPN":"コハルの言うとおりよ。今は仲いいところを見せましょう。","ENG":"Sobin's right. Let's try to look friendly for now.","TWN":"素蘋說得對，現在要展現感情好的樣子。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아~ 랜즈캡이 씌워져 있었네. 이제 잘 보일 거야.","JPN":"あ、レンズキャップを外してなかったのね。これでちゃんと映るはずよ。","ENG":"Ah! The lens cap was still on. There we go.","TWN":"啊～原來是鏡頭蓋沒打開。現在應該能拍了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아하하, 안녕하세요 사장님. 조금 소란스러운 오프닝이었죠?","JPN":"あはは、お疲れ様です、社長。少し騒がしいオープニングでしたね。","ENG":"Ahaha. Hi, Boss. Quite the chaotic opening, right?","TWN":"啊哈哈，老闆好。開場有點吵吵鬧鬧的吧？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"오늘은 사장님의 생일을 맞아 저희 알트소대가 깜짝 이벤트를 준비해 봤답니다.","JPN":"社長の誕生日を迎えて、今日は私たちアルト小隊がサプライズイベントを用意しました。","ENG":"To celebrate your birthday, Alt Squad has prepared a little surprise for you today.","TWN":"今天是老闆的生日，我們阿爾特小隊準備了一個驚喜活動。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"생일 축하해요 사장님. 이번 영상으로 두 번이나 축하하게 되네요.","JPN":"お誕生日おめでとうございます、社長。映像でお祝いするのはこれで2度目ですね。","ENG":"Happy birthday, Boss. This makes it the second birthday video I've made for you.","TWN":"生日快樂，老闆。算上這支影片，已經是第二次幫您慶祝了呢。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이번에도 저희 알트소대가 돈을 모아 선물을 준비했답니다.","JPN":"今回も私たちアルト小隊がお金を集めて、プレゼントを用意しました。","ENG":"We pooled our money again and prepared a present for you this year too.","TWN":"這次我們阿爾特小隊一起集資準備了禮物。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저번보다 훨~씬 더 호화로운 선물이니까 기대하고 열어주세요?","JPN":"前回よりずうっと豪華なプレゼントですから、楽しみにしてくださいね。","ENG":"It's far more extravagant than last time, so please look forward to it when you open it, okay?","TWN":"比上次還～要更豪華，請滿懷期待打開吧？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"후후, 딱 한 번 축하하고 빠진 <color=#ffd34c>누구</color>와는 확연히 다른 대우죠?","JPN":"ふふ、1度お祝いしたきりで抜けた<color=#ffd34c>誰かさん</color>とは大違いでしょう？","ENG":"Hehe. Quite a contrast from a <color=#ffd34c>certain someone</color> who showed up once and vanished, wouldn't you say?","TWN":"呵呵，和只祝賀一次就跑掉的<color=#ffd34c>某人</color>差很多呢？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이제 각자 돌아가면서 한마디씩 해볼까?","JPN":"じゃあ、みんなも一言ずつ言っていこうか。","ENG":"Now, why don't we go around and have everyone say something?","TWN":"就大家輪流說句話吧？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"으, 응……!","JPN":"う、うん……！","ENG":"O-okay...!","TWN":"呃、嗯……！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"새, 생일 축하드려요 사장님.","JPN":"お、お誕生日おめでとうございます、社長。","ENG":"H-happy birthday, Boss.","TWN":"生、生日快樂，老闆。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"이번 생일은 꼭 직접 축하드리고 싶었어요. 사장님껜 감사한 마음이 정말 많으니까요.","JPN":"今年の誕生日は絶対に、ちゃんとした形でお祝いしたかったんです。社長には本当に感謝していますから。","ENG":"I really wanted to say it in person this year. I have so much to thank you for.","TWN":"這次我想親自祝您生日快樂，因為我真的很感謝您。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"서, 선물도 좋지만 맛있는 음식도 좋아하시죠? 저희 소대원들이 좋아하는 요리가 있는데 원하시면 얼마든지 대접해 드릴게요……!","JPN":"プ、プレゼントもいいけど、おいしい食べ物もお好きですよね？　小隊員みんなが大好きな料理があるんですけど、よかったらご馳走します……！","ENG":"G-gifts are nice, but you like good food too... right? We also have a few favorite dishes, and if you want, we could make them for you anytime...!","TWN":"那、那個雖然禮物很好，但您也喜歡美食吧？這裡有我們小隊員最愛的菜色。如果您喜歡，隨時都可以招待您……！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그, 그럼 앞으로도 잘 부탁드리겠습니다……! 저도 많이 노력할게요!","JPN":"そ、それじゃこれからもよろしくお願いします……！　私ももっと頑張ります！","ENG":"S-so thank you...! And I'll keep doing by best!","TWN":"那、那麼今後也請多多指教……！我也會更努力的！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"크흠! 다음은 내가 할게!","JPN":"ゴホン！　次は俺だな！","ENG":"Ahem! I'll go next.","TWN":" 咳！下一個換我！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L31_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"어이 사장님, 생일 축하한다고! 깜짝 놀랐지? 하하.","JPN":"おい、社長。誕生日おめでとう！　びっくりしただろ？　ははっ。","ENG":"Hey, Boss. Happy birthday! Bet you didn't expect this, right? Haha.","TWN":"喂老闆，生日快樂啦！嚇到了吧？哈哈。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"생일이면 생일이라고 미리 좀 말해주지~ 대장 아니었으면 그냥 넘어갈 뻔했잖아.","JPN":"誕生日なんだったらもっと前から言ってくれよな～　隊長が教えてくれなかったら知らないまま終わってたぜ。","ENG":"You should tell us ahead of time when it's your birthday. If it weren't for Cap, I would've missed it completely.","TWN":"生日應該要早點說嘛～要不是隊長，差點就這樣過去了。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"어 그러니까…… 음…… 이제 무슨 말을 해야 하지?","JPN":"ええと、だから……うーん……あとは何を言えばいいんだ？","ENG":"Uh, so... um... What am I supposed to say now?","TWN":"呃所以說……嗯……接下來該說什麼？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"아참! 탕비실에 간식 종류가 더 늘었으면 좋겠어! 회식비도 많이 지원해 주면 좋고!","JPN":"あ、そうだ！　給湯室のおやつ、もっと種類を増やしてくれ！　会食の予算も増やしてくれたらもっとありがたい！","ENG":"Oh, right! I want more snacks in the break room. And bigger budgets for team dinners!","TWN":"啊對了！希望茶水間的零食種類可以多一點！還要多補助一點聚餐費用！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아하하, 그건 유진이 생일 때 부탁해 보면 어떨까?","JPN":"あはは、それはシロコの誕生日に頼んだほうがいいんじゃない？","ENG":"Ahaha. How about saving that request for your own birthday, Eujin?","TWN":"哈哈，那個不如等劉珍生日的時候再說吧？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"아…… 그, 그런가……?","JPN":"あ……そ、そうか……？","ENG":"Oh... Y-you think so...?","TWN":"啊……是、是這樣嗎……？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"돼지같이 먹을 거나 부탁하긴.","JPN":"イノシシらしく、食べ物に目がないのね。","ENG":"Asking for food like some kind of pig.","TWN":"真像隻豬，只會想到吃。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"흠흠. 생일 축하드립니다 사장님.","JPN":"ゴホン、お誕生日おめでとうございます、社長。","ENG":"Ahem. Happy birthday, Boss.","TWN":"咳咳。祝您生日快樂，老闆。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"생일날이 아니더라도 사장님껜 드리고 싶은 말이 정말 많았어요.","JPN":"誕生日じゃなくても、社長には話したいことがたくさんあります。","ENG":"There are a lot of things I've wanted to say to you even outside of your birthday.","TWN":"即使不是生日，我也有很多話想對您說。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"항상 저희 알트 소대를 생각해 주셔서 진심으로 감사드립니다.","JPN":"いつも私たちアルト小隊に色々と気を遣ってくださって、本当にありがとうございます。","ENG":"Thank you for always looking out for Alt Squad.","TWN":"真的非常感謝您一直以來這麼照顧我們阿爾特小隊。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"사장님 덕분에 전과는 비교도 할 수 없을 정도로 좋은 생활을 보낼 수 있었어요.","JPN":"社長のおかげで、以前とは比べものにならないほど快適な生活ができています。","ENG":"Because of you, my life now is incomparable to what it used to be.","TWN":"多虧老闆，我現在的生活好到和以前完全無法相比。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"맡길 임무가 있다면 언제든 말씀해 주세요.","JPN":"任せたいことがあったら、いつでも仰ってくださいね。","ENG":"If there's ever a mission you need handled, just say the word.","TWN":"如果有任何任務交付，請隨時吩咐我們。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"사장님은 저희들의 대장과 더불어, 의지할 수 있는 사람이니까요.","JPN":"社長は隊長と同じく頼りになる人ですから。","ENG":"To us, you're someone we can rely on. Right alongside Cap.","TWN":"老闆不只是我們隊長，也是我們可以依靠的人。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"후후 잘했어 얘들아. 사장님께서 정말 기뻐하실 거야.","JPN":"ふふ。みんなよくやったわ。社長もきっと喜んでくれると思うの。","ENG":"Very good, everyone. I'm sure he'll be delighted.","TWN":"呵呵，大家都做得很好。老闆一定會很開心。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이제 다 같이 마무리하자. 여기 모여 줄래?","JPN":"締めの挨拶はみんなでやりましょう。ちょっとここに集まってくれる？","ENG":"Let's wrap up together. Could everyone come in close?","TWN":"那就一起來收尾吧。可以靠過來嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그럼 내가 여기 설래!","JPN":"じゃあ俺はここだ！","ENG":"Then I wanna stand right here!","TWN":"那我站這裡！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L1_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"으앗, 나 여기 있는데……!","JPN":"ああっ、私もういるよ……！","ENG":"Whoa! Hey, that's my spot...!","TWN":"呃啊，我在這裡耶……！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L4_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"엇, 미안. 쭈그리고 있는지 몰랐어.","JPN":"えっ、悪い。屈んでて見えなかった。","ENG":"Oh, my bad. Didn't see you crouching there.","TWN":"啊，抱歉。我沒看到你蹲著。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그 육중한 몸 때문에 카메라에 다 잡히긴 하는 건지 모르겠네.","JPN":"図体がデカすぎて、カメラに全部収まるか心配ね。","ENG":"I'm not even sure that massive body of yours fits in the frame.","TWN":"也不知道你那魁梧的身材會不會害相機拍不了全部。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"하! 그러는 니는 하도 말라서 보이지도 않겠다!","JPN":"はっ！　そういうお前こそ、ガリガリすぎてちゃんと映らないんじゃねえか？","ENG":"Ha! Says you. You're so scrawny the camera might not even register you!","TWN":"哈！你那麼瘦，根本看不到！"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"마른 거랑 카메라에 보이는 거랑 뭔 상관이야. 이 바보 돼지야!","JPN":"痩せているのとカメラの映り具合は何の関係もないでしょう、バカイノシシ！","ENG":"What does being skinny have to do with camera visibility, you stupid pig!","TWN":"瘦不瘦跟拍不拍得到有什麼關係啊，你這笨豬！"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"앙? 진짜 해보자는……!","JPN":"ああ？　やんのかこら……！","ENG":"Oh? You want to go right now...?!","TWN":"啊？你玩真的啊……！"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L12_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"어, 얼래? 왜 카메라가 갑자기 꺼진 거지?","JPN":"あ、あれ？　カメラの電源が急に落ちた？","ENG":"H-huh? Why did the camera suddenly turn off?","TWN":"咦、欸？相機怎麼突然關了？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"무식하게 난동 부리니까 또 고장 낸 거잖아 이 돼지야!","JPN":"暴れるからまた壊れてしまったじゃない、イノシシ！","ENG":"Because you went on another rampage like a brute and broke it again, you pig!","TWN":"都怪你亂弄，又把它弄壞了吧，你這豬頭！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"여, 영상은 파일로 전달해 드리면 되는 거니까 괜찮을 거야 얘들아…….","JPN":"え、映像はデータで渡せばいいから、きっと大丈夫だよ……","ENG":"I-I think it's okay... We can just send the file later...","TWN":"影……影片之後把檔案傳給老闆就好了，不會有問題……"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……너희들은 하루만 안 싸워주는 게 최고의 선물일지도 모르겠어.","JPN":"……あなたたちが1日でも喧嘩せずにいてくれることが、最高のプレゼントかもしれないわね。","ENG":"...Honestly, the best birthday present you two could give him is just one day without fighting.","TWN":"……你們一天不吵架說不定才是最好的禮物。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};